16→	@Get()
17→	@ApiOperation({
18→		summary: 'Search products using natural language via neural embeddings',
19→	})
20→	@ApiResponse({
21→		status: 200,
22→		description: 'Returns semantically relevant products',
23→		type: NeuralSearchResponseDto,
24→	})
