27→		paramFormatter: (params: [NeuralSearchQueryDto]) => ({
28→			q: params[0].q,
29→			limit: params[0].limit,
30→		}),
31→		responseFormatter: (response: NeuralSearchResponseDto) => ({
32→			total: response.total,
33→		}),
34→	})
35→	async search(@Query() query: NeuralSearchQueryDto): Promise<NeuralSearchResponseDto> {
36→		return this.neuralSearchService.search({ query });
37→	}
38→
39→	@Get('view')
40→	@ApiOperation({ summary: 'Visual HTML view of neural search results' })
41→	@ApiResponse({ status: 200, description: 'Returns HTML page with product cards' })
42→	@Header('Content-Type', 'text/html')
43→	async view(@Query('q') q?: string, @Query('limit') limit?: string): Promise<string> {
44→		if (!q) {
45→			return this.neuralSearchService.renderSearchPageHtml({ result: null });
46→		}
47→
48→		const query: NeuralSearchQueryDto = {
49→			q,
50→			...(limit !== undefined && { limit: Number(limit) }),
51→		};
52→		const result = await this.neuralSearchService.search({ query });
53→
54→		return this.neuralSearchService.renderSearchPageHtml({ result });
55→	}
