24→		query,
25→	}: {
26→		query: NeuralSearchQueryDto;
27→	}): Promise<NeuralSearchResponseDto> {
28→		const products = await this.opensearchNeuralService.searchProducts({
29→			queryText: query.q,
30→			...(query.limit !== undefined && { size: query.limit }),
31→		});
32→
33→		return {
34→			query: query.q,
35→			total: products.length,
36→			products,
