 23→@Injectable()
 24→export class OpensearchNeuralService implements OnModuleInit {
 25→	private readonly logger = new Logger(OpensearchNeuralService.name);
 26→	private indexName: string;
 27→	private modelId: string | null = null;
 28→
 29→	constructor(
 30→		private readonly opensearchService: OpensearchService,
 31→		private readonly configService: EnvConfigService,
 32→	) {}
