297→	async searchProducts({
298→		queryText,
299→		size = NEURAL_SEARCH_LIMIT,
300→	}: {
301→		queryText: string;
302→		size?: number;
303→	}): Promise<IOpensearchProduct[]> {
304→		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
305→		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
306→		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
307→		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
308→		const brand = this.detectBrand({ text: sanitizedQuery });
309→
310→		const baseFilters: object[] = [{ term: { status: 'active' } }];
311→
312→		if (genderProductTypes) {
313→			baseFilters.push({ terms: { product_type: genderProductTypes } });
314→		}
315→
316→		const priceBoosts: object[] =
317→			priceLevels?.map((level) => ({
318→				term: { price_level: { value: level, boost: 1.5 } },
319→			})) ?? [];
320→
321→		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand], boost: 2 } }] : [];
322→
323→		const hits = await this.opensearchService.search({
324→			indexName: this.indexName,
325→			searchPipeline: 'hybrid-search-pipeline',
326→			body: {
327→				size,
328→				min_score: 0.4,
329→				query: {
330→					hybrid: {
331→						queries: [
332→							{
333→								bool: {
334→									should: [
335→										{
336→											match_phrase: {
337→												general_comments: { query: normalizedQuery, boost: 0.1 },
338→											},
339→										},
340→										{
341→											match_phrase: { features: { query: normalizedQuery, boost: 0.1 } },
342→										},
343→										{ match_phrase: { name: { query: normalizedQuery, boost: 0.1 } } },
344→										...priceBoosts,
345→										...brandBoosts,
346→									],
347→									filter: baseFilters,
348→								},
349→							},
350→							{
351→								neural: {
352→									product_embedding: {
353→										query_text: normalizedQuery,
354→										model_id: this.getModelId(),
355→										k: size * 5,
356→										filter: { bool: { filter: baseFilters } },
357→									},
358→								},
359→							},
360→						],
361→					},
362→				},
363→				collapse: { field: 'product_id' },
364→				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
365→			},
366→		});
367→
368→		return hits.map((hit) => ({
369→			...(hit._source as IOpensearchProduct),
370→			_id: hit._id,
371→		}));
372→	}
