400→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
401→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
402→			condensedFeatures: style.condensed_features,
403→		});
404→		const priceLvlMap: Record<string, string> = {
405→			1: 'Budget',
406→			2: 'Mid-range',
407→			3: 'Premium',
408→		};
409→		const mappedPriceLevel: string | null =
410→			style.price_level && priceLvlMap[String(style.price_level)]
411→				? (priceLvlMap[String(style.price_level)] ?? null)
412→				: (priceLvlMap['2'] ?? null);
413→
414→		const parts: string[] = [
415→			...(style.name ? [this.cleanText({ text: style.name })] : []),
416→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
417→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
418→			...(style.brand?.length
419→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
420→				: []),
421→			...(normalizedCondensedFeatures?.length
422→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
423→				: []),
424→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
425→			...(style.primary_category_name
426→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
427→				: []),
428→			...(style.manufacturer
429→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
430→				: []),
431→			...(style.sub_category_names?.length
432→				? [
433→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
434→					]
435→				: []),
436→			...(style.decoration_method
437→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
438→				: []),
439→			...(style.features
440→				? [`Features: ${this.cleanText({ text: style.features })}`]
441→				: []),
442→		];
443→
444→		const combinedText = parts.filter(Boolean).join('. ');
445→
446→		this.logger.debug(
447→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
448→		);
449→
450→		return combinedText;
451→	}
